public void insert()
{
    next insert();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        str descriptiveKeyCollection = strFmt("CityKey ='%1'",this.CityKey);

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("AddressCities");
        contract.parmOperationType("Insert");

        ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);

        eventClass.send();
    }
}

public void update()
{
    LogisticsAddressCity orignalCity = this.orig();

    next update();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {

        str oldCityValue = "";

        if (this.Name != orignalCity.Name)
        {
            oldCityValue = orignalCity.Name;
        }
        else
        {
            oldCityValue = this.Name;
        }

        str descriptiveKeyCollection = strFmt("CityKey ='%1',oldCityValue = '%2'",this.CityKey,oldCityValue);

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("AddressCities");
        contract.parmOperationType("Update");

        ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);

        eventClass.send();
    }
}
